/// Boot logo renderer.
enum BootLogo {
    static func draw(fb: Framebuffer) {
        copyChunk(BootLogoData.chunk0, to: fb, offset: 0)
        copyChunk(BootLogoData.chunk1, to: fb, offset: 6000)
        copyChunk(BootLogoData.chunk2, to: fb, offset: 12000)
        copyChunk(BootLogoData.chunk3, to: fb, offset: 18000)
        copyChunk(BootLogoData.chunk4, to: fb, offset: 24000)
        copyChunk(BootLogoData.chunk5, to: fb, offset: 30000)
        copyChunk(BootLogoData.chunk6, to: fb, offset: 36000)
        copyChunk(BootLogoData.chunk7, to: fb, offset: 42000)
    }

    private static func copyChunk(_ chunk: StaticArray6000, to fb: Framebuffer, offset: Int) {
        withUnsafePointer(to: chunk.storage) { ptr in
            fb.copyToNativeBuffer(
                from: UnsafeRawPointer(ptr).assumingMemoryBound(to: UInt8.self),
                offset: offset, count: 6000)
        }
    }
}